#include<bits/stdc++.h>
using namespace std;
long long a[2001][2001],sum[3001],dp[101][301];
const long long mod=998244353;
int main()
{
    long long ans=1;
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        for(long long j=1;j<=m;j++)
        {
            scanf("%lld",&a[i][j]);
            sum[i]=(sum[i]+a[i][j])%mod;
        }
        ans=((ans*((sum[i]+1)%mod+mod))%mod+mod)%mod;
    }
    ans=((ans-1)%mod+mod)%mod;
    for(long long c=1;c<=m;c++)
    {
        memset(dp,0,sizeof(dp));
        dp[0][n]=1;
        for(long long i=1;i<=n;i++)
        {
            for(long long j=n-i;j<=n+i;j++)
            {
                dp[i][j]=(dp[i-1][j]+dp[i-1][j-1]*a[i][c]%mod+dp[i-1][j+1]*((sum[i]-a[i][c])%mod+mod)%mod)%mod;
            }
        }
        for(long long i=n+1;i<=n*2;i++)
        {
            ans=((ans-dp[n][i])%mod+mod)%mod;
        }
    }
    printf("%lld",ans);
    return 0;
}
